const getPingAlertMetricSummary = `-- name: GetPingAlertMetricSummary :one
SELECT count(*) FILTER (
           WHERE CASE
               WHEN $1::text IN ('ping.average_rtt_ms') THEN rtt_avg_ms IS NOT NULL
               WHEN $1::text IN ('ping.max_rtt_ms') THEN rtt_max_ms IS NOT NULL
               ELSE true
           END
       )::bigint AS samples,
       coalesce(CASE $1::text
           WHEN 'ping.loss_percent' THEN avg(loss_percent)::double precision
           WHEN 'ping.success_rate' THEN (100.0 * count(*) FILTER (WHERE status = 'successful') / NULLIF(count(*), 0))::double precision
           WHEN 'ping.average_rtt_ms' THEN avg(rtt_avg_ms)::double precision
           WHEN 'ping.max_rtt_ms' THEN max(rtt_max_ms)::double precision
           ELSE NULL::double precision
       END, 0)::double precision AS value
FROM ping_results
WHERE probe_id = $2
  AND check_id = $3
  AND started_at >= $4
  AND started_at < $5
`

