const getTCPAlertMetricSummary = `-- name: GetTCPAlertMetricSummary :one
SELECT count(*) FILTER (
           WHERE CASE
               WHEN $1::text IN ('tcp.average_connect_ms', 'tcp.max_connect_ms') THEN connect_duration_ms IS NOT NULL
               ELSE true
           END
       )::bigint AS samples,
       coalesce(CASE $1::text
           WHEN 'tcp.failure_percent' THEN (100.0 * count(*) FILTER (WHERE status IN ('timeout', 'error')) / NULLIF(count(*), 0))::double precision
           WHEN 'tcp.success_rate' THEN (100.0 * count(*) FILTER (WHERE status = 'successful') / NULLIF(count(*), 0))::double precision
           WHEN 'tcp.average_connect_ms' THEN avg(connect_duration_ms)::double precision
           WHEN 'tcp.max_connect_ms' THEN max(connect_duration_ms)::double precision
           ELSE NULL::double precision
       END, 0)::double precision AS value
FROM tcp_results
WHERE probe_id = $2
  AND check_id = $3
  AND started_at >= $4
  AND started_at < $5
`

type GetTCPAlertMetricSummaryParams struct {
	Metric         string    `json:"metric"`
	ProbeStorageID int64     `json:"probe_storage_id"`
	CheckStorageID int64     `json:"check_storage_id"`
	StartedAtFrom  time.Time `json:"started_at_from"`
	StartedAtTo    time.Time `json:"started_at_to"`
}

type GetTCPAlertMetricSummaryRow struct {
	Samples int64   `json:"samples"`
	Value   float64 `json:"value"`
}

func (q *Queries) GetTCPAlertMetricSummary(ctx context.Context, arg GetTCPAlertMetricSummaryParams) (GetTCPAlertMetricSummaryRow, error) {
	row := q.db.QueryRow(ctx, getTCPAlertMetricSummary,
		arg.Metric,
		arg.ProbeStorageID,
		arg.CheckStorageID,
		arg.StartedAtFrom,
		arg.StartedAtTo,
	)
	var i GetTCPAlertMetricSummaryRow
	err := row.Scan(&i.Samples, &i.Value)
	return i, err
}

